def safe_int(campo: str, valor: str):
    texto = valor.strip()
    if texto == "":
        return (False, None, f"{campo} vacío: {valor!r}")
    try:
        return (True, int(texto), None)
    except ValueError:
        return (False, None, f"{campo} no es entero: {valor!r}")

for v in [" 21 ", "", "abc", "  "]:
    print(repr(v), "→", safe_int("edad", v))

from decimal import Decimal, InvalidOperation, ROUND_HALF_UP

def parse_pipeline(edad_raw: str, monto_raw: str) -> dict:
    raw = {"edad": edad_raw, "monto": monto_raw}
    clean = {"edad": None, "monto": None}
    errors = []
    et = edad_raw.strip()
    if not et:
        errors.append("edad vacía")
    else:
        try:
            clean["edad"] = int(et)
        except ValueError:
            errors.append(f"edad no entera: {edad_raw!r}")
    mt = monto_raw.strip().replace(",", ".")
    if not mt:
        errors.append("monto vacío")
    else:
        try:
            d = Decimal(mt)
            if not d.is_finite():
                raise InvalidOperation
            clean["monto"] = d.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        except (InvalidOperation, ValueError):
            errors.append(f"monto inválido: {monto_raw!r}")
    return {"raw": raw, "clean": clean, "errors": errors}

casos = [
    (" 34 ", "150.5"),
    ("x", "99,00"),
    ("", "abc"),
]
for e, m in casos:
    print(parse_pipeline(e, m))

