def prompt_int(label: str, raw: str):
    texto = raw.strip()
    if texto == "":
        return None, f"{label} vacío"
    try:
        return int(texto), None
    except ValueError:
        return None, f"{label} no es entero: {raw!r}"

for lab, r in [("edad", " 21 "), ("edad", "x"), ("edad", "  ")]:
    print(lab, r, "→", prompt_int(lab, r))
